mapper.select:
SELECT COUNT(*)
FROM TB_LMS_DSCS_ATCL
WHERE DSCS_ID = #{dscsId}
  AND RGTR_ID = #{rgtrId}
  AND DELYN = 'N'

SELECT COUNT(*) FROM TB_LMS_DSCS_ATCL A LEFT JOIN TB_LMS_USER U ON U.USER_ID = A.RGTR_ID WHERE A.DSCS_ID = #{dscsId}
AND (A.DELYN IN ('N', 'H') OR EXISTS ( SELECT 1 FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ATCL_ID = A.DSCS_ATCL_ID AND C.DELYN = 'N' ))
AND ( LOWER(A.RGTR_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(U.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.USER_ID IN
#{item}

SELECT ROW_NUMBER() OVER (ORDER BY A.ATCL_SEQNO ASC, A.REG_DTTM DESC) AS LINE_NO , A.DSCS_ATCL_ID , A.DSCS_ID , A.UP_DSCS_ATCL_ID , NVL(A.ATCL_LV, 0) AS ATCL_LV , NVL(A.ATCL_SEQNO, 0) AS ATCL_SEQNO , A.DSCS_ATCL_TYCD , A.OKNOK_GBNCD , A.ATCL_TTL , A.ATCL_CTS , A.ATCL_CTS_LEN , NVL(A.INQ_CNT, 0) AS INQ_CNT , U.USERNM , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , A.EDTR_USEYN , A.DELYN , A.USER_ID , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ATCL_ID = A.DSCS_ATCL_ID AND C.DELYN = 'N') AS cmntCount , (SELECT COUNT(*) FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ATCL_ID = A.DSCS_ATCL_ID AND C.DELYN = 'N' AND C.USER_ID = A.USER_ID) AS myCmntCount , (SELECT MAX(B.ATCL_SEQNO) FROM TB_LMS_DSCS_ATCL B WHERE B.DSCS_ID = A.DSCS_ID AND B.DELYN = 'N') AS maxOdr , '' AS phtFileByte FROM TB_LMS_DSCS_ATCL A LEFT JOIN TB_LMS_USER U ON U.USER_ID = A.RGTR_ID WHERE A.DSCS_ID = #{dscsId}
AND (A.DELYN IN ('N', 'H') OR EXISTS ( SELECT 1 FROM TB_LMS_DSCS_CMNT C WHERE C.DSCS_ATCL_ID = A.DSCS_ATCL_ID AND C.DELYN = 'N' ))
AND ( LOWER(A.RGTR_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(U.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.USER_ID IN
#{item}
ORDER BY A.ATCL_SEQNO ASC, A.REG_DTTM DESC

mapper.insert:
INSERT INTO TB_LMS_DSCS_ATCL (
      DSCS_ATCL_ID
    , DSCS_ID
    , USER_ID
    , UP_DSCS_ATCL_ID
    , ATCL_LV
    , ATCL_SEQNO
    , DSCS_ATCL_TYCD
    , OKNOK_GBNCD
    , ATCL_TTL
    , ATCL_CTS
    , ATCL_CTS_LEN
    , INQ_CNT
    , EDTR_USEYN
    , DELYN
    , RGTR_ID
    , REG_DTTM
    , MDFR_ID
    , MOD_DTTM
) VALUES (
      #{dscsAtclId}
    , #{dscsId}
    , #{userId}
    , #{upDscsAtclId}
    , 0
    , #{atclSeqno}
    , #{dscsAtclTycd}
    , #{oknokGbncd}
    , #{atclTtl}
    , #{atclCts}
    , #{atclCtsLen}
    , 0
    , 'N'
    , 'N'
    , #{userId}
    , FN_DTTM()
    , #{userId}
    , FN_DTTM()
)

mapper.update:
UPDATE TB_LMS_DSCS_ATCL
SET MDFR_ID = #{mdfrId}
  , MOD_DTTM = FN_DTTM()

  , UP_DSCS_ATCL_ID = #{upDscsAtclId}


  , ATCL_LV = #{atclLv}


  , ATCL_SEQNO = #{atclSeqno}


  , DSCS_ATCL_TYCD = #{dscsAtclTycd}


  , OKNOK_GBNCD = #{oknokGbncd}


  , ATCL_TTL = #{atclTtl}


  , ATCL_CTS = #{atclCts}
  , ATCL_CTS_LEN = #{atclCtsLen}


  , INQ_CNT = #{inqCnt}


  , EDTR_USEYN = #{edtrUseyn}


  , DELYN = #{delyn}

WHERE DSCS_ATCL_ID = #{dscsAtclId}
  AND DSCS_ID = #{dscsId}

UPDATE TB_LMS_DSCS_ATCL
SET DELYN = 'Y'
  , MDFR_ID = #{mdfrId}
  , MOD_DTTM = FN_DTTM()
WHERE DSCS_ATCL_ID = #{dscsAtclId}
  AND DSCS_ID = #{dscsId}

UPDATE TB_LMS_DSCS_ATCL
SET DELYN = 'H'
  , MDFR_ID = #{mdfrId}
  , MOD_DTTM = FN_DTTM()
WHERE DSCS_ATCL_ID = #{dscsAtclId}
  AND DSCS_ID = #{dscsId}
